import{_ as o,o as t,c as a,ak as n}from"./chunks/framework.Bb9ZXUwF.js";const p=JSON.parse('{"title":"Tagging and versioning conventions","description":"","frontmatter":{},"headers":[],"relativePath":"versioning.md","filePath":"versioning.md"}'),s={name:"versioning.md"};function r(i,e,d,c,l,g){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="tagging-and-versioning-conventions" tabindex="-1">Tagging and versioning conventions <a class="header-anchor" href="#tagging-and-versioning-conventions" aria-label="Permalink to “Tagging and versioning conventions”">​</a></h1><h2 id="tag-format" tabindex="-1">Tag format <a class="header-anchor" href="#tag-format" aria-label="Permalink to “Tag format”">​</a></h2><p>Release tags must match the workflow filter in <code>tag.yml</code> (<code>**/v*</code>) and encode both the <strong>Nx project name</strong> and <strong>semver</strong>:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&lt;nx-project-name&gt;/v&lt;semver&gt;</span></span></code></pre></div><p><strong>Rules:</strong></p><ul><li><code>&lt;nx-project-name&gt;</code> must be the <strong>exact</strong> Nx project name (<code>npx nx show projects</code>). Example: <code>bcew-blocks</code>.</li><li><code>&lt;semver&gt;</code> is prefixed with <code>v</code> in the tag. Examples: <code>v1.0.0</code>, <code>v1.1.0-a1</code> (Composer-compatible prerelease segments are allowed when <code>tag.yml</code> and Composer both accept them).</li><li>Invalid examples: <ul><li>Wrong project slug not in Nx graph</li><li>Non-semver suffixes such as <code>v100-testing-tag</code> for production consumption</li></ul></li></ul><p>The workflow strips the leading <code>v</code> for the version recorded in <code>packages.json</code> while keeping the full tag for GitHub Release URLs.</p><h2 id="branch-naming" tabindex="-1">Branch naming <a class="header-anchor" href="#branch-naming" aria-label="Permalink to “Branch naming”">​</a></h2><p>Use descriptive, lowercase, hyphenated branches:</p><table tabindex="0"><thead><tr><th>Prefix</th><th>Use</th></tr></thead><tbody><tr><td><code>feature/</code></td><td>New functionality</td></tr><tr><td><code>fix/</code> or <code>bugfix/</code></td><td>Defect fixes</td></tr><tr><td><code>chore/</code></td><td>Tooling, housekeeping</td></tr><tr><td><code>docs/</code></td><td>Documentation only</td></tr></tbody></table><p>Examples: <code>feature/add-hero-block</code>, <code>fix/wp-env-port-conflict</code>.</p><p><strong>Default branch:</strong> <code>main</code> — PRs usually target <code>main</code>; <code>nx.json</code> sets <code>defaultBase</code> to <code>origin/main</code> for local <code>nx affected</code> comparisons.</p><h2 id="releases-and-prereleases" tabindex="-1">Releases and prereleases <a class="header-anchor" href="#releases-and-prereleases" aria-label="Permalink to “Releases and prereleases”">​</a></h2><p><code>tag.yml</code> currently marks GitHub Releases as <strong>prerelease</strong> (<code>prerelease: true</code> in the workflow). Adjust workflow YAML when the program moves to stable release semantics.</p><h2 id="wordpress-version-on-release" tabindex="-1">WordPress version on release <a class="header-anchor" href="#wordpress-version-on-release" aria-label="Permalink to “WordPress version on release”">​</a></h2><p>When <strong><code>tag.yml</code></strong> runs for a tag like <code>bcew-theme-2/v1.4.0</code>:</p><ol><li>The workflow parses the tag into project name (<code>bcew-theme-2</code>) and version (<code>1.4.0</code>).</li><li>Source files in the repository are <strong>not</strong> modified.</li><li><strong>Only if the version is <code>X.Y.Z</code></strong> (three numbers, e.g. <code>1.2.3</code>), the release <strong><code>dist.zip</code></strong> gets the version field updated: <ul><li><strong>Theme</strong> — <code>Version:</code> line in <code>style.css</code></li><li><strong>Plugin</strong> — <code>* Version:</code> line in <code>&lt;nx-project-name&gt;.php</code></li></ul></li><li>That updated file exists only inside <strong><code>dist.zip</code></strong> attached to the GitHub Release.</li></ol><p>Tags with other version shapes (for example <code>1.2.3-beta.1</code> or <code>0.0.1-test</code>) still release, but skip the version update step.</p><p>You do not need to edit the version by hand before tagging for <code>X.Y.Z</code> releases. The placeholder in source (e.g. <code>1.0.0</code>) can stay as-is.</p><h2 id="communicating-version-bumps" tabindex="-1">Communicating version bumps <a class="header-anchor" href="#communicating-version-bumps" aria-label="Permalink to “Communicating version bumps”">​</a></h2><ul><li>Document breaking changes in package <code>docs/</code> or changelog files as agreed by the team.</li></ul>',21)])])}const m=o(s,[["render",r]]);export{p as __pageData,m as default};
